function calc(items: Item[], itemCount: number): number {
  let total = 0;
  for (let index = 0; index < itemCount; index++) {
    total += items[index].count;
  }
  return total;
}

function canUserProceed(user: User | null): boolean {
  return user !== null && user.isActive && !user.isBlocked;
}

async function getData(id: string): Promise<unknown> {
  const response = await fetch(`/api/${id}`);
  const data = await response.json();
  return data;
}
